//! Static font metric data extracted from DejaVu TTF files.
//!
//! Auto-generated by gen_font_data.py — do not edit manually.
//!
//! This replaces runtime TTF parsing with pre-extracted static tables,
//! eliminating the need to embed 2.5 MB of TTF data and the ttf-parser dependency.
//!
//! Vendored from the sister project
//! [plantuml-little](https://github.com/kookyleo/plantuml-little) at commit
//! `b32d6aa`. Regenerate from the same DejaVu TTFs if metric values ever
//! need to be re-derived.

/// Metadata for a single font face.
#[derive(Debug, Clone, Copy)]
pub struct FontMeta {
    pub units_per_em: u16,
    pub ascender: i16,
    pub descender: i16,
    pub typo_ascender: i16,
    /// Range table: sorted by start codepoint, (start, end, advance).
    /// Binary search on `start` to find the range containing a codepoint.
    ranges: &'static [(u32, u32, u16)],
}

impl FontMeta {
    /// Look up the horizontal advance for a Unicode codepoint.
    /// Returns `None` if the codepoint has no glyph in this font.
    #[inline]
    pub fn glyph_advance(&self, codepoint: u32) -> Option<u16> {
        // Binary search for the range containing this codepoint
        let idx = self
            .ranges
            .partition_point(|&(start, _, _)| start <= codepoint);
        if idx == 0 {
            return None;
        }
        let (start, end, adv) = self.ranges[idx - 1];
        if codepoint >= start && codepoint <= end {
            Some(adv)
        } else {
            None
        }
    }
}

